import React from 'react';
import {Link} from 'react-router-dom';
import { BASE_PATH } from '../../App';
import './CardItem.css'

const CardItem = ({ text, path, external }) => {
  // External cards are static files outside the router — use a plain <a>.
  const inner = (
    <div className="cards_item_info">
    <h5 className="cards_item_text">{text}</h5>
    </div>
  );

  return (
    <>
    <li className="card-item" id="card-item">
    { external
      ? <a className="cards_item_link" href={BASE_PATH + path}>{inner}</a>
      : <Link className="cards_item_link" to={path}>{inner}</Link>
    }
    </li>
    </>
    )
}

export default CardItem;

